import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";

const server = new McpServer({ name: "crm-server", version: "1.0.0" });

// Tool with complex schema and proper error handling
server.tool(
  "search_customers",
  // Description is what Claude reads to decide when to call this tool.
  // Be specific: what does it do, when to use it, what does it return.
  `Search the CRM customer database by name, email, or company.
   Use when the user asks about a specific account or wants to find contacts.
   Returns up to 20 matching records with id, name, email, and status.`,
  {
    query: z.string().min(1).describe("Name, email, or company to search for"),
    limit: z.number().int().min(1).max(50).default(20),
    includeInactive: z.boolean().default(false),
  },
  async ({ query, limit, includeInactive }) => {
    try {
      const results = await db.customers.search({ query, limit, includeInactive });
      return {
        content: [{ type: "text", text: JSON.stringify(results, null, 2) }],
        isError: false,
      };
    } catch (error) {
      // Do NOT throw - throwing crashes the session.
      // Return errors as content with isError: true so Claude can recover.
      return {
        content: [{ type: "text", text: `Search failed: ${error.message}` }],
        isError: true,
      };
    }
  }
);

