import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { ResourceTemplate } from "@modelcontextprotocol/sdk/server/mcp.js";
import fs from "fs/promises";
import path from "path";

const server = new McpServer({ name: "notes-server", version: "1.0.0" });
const NOTES_DIR = "/var/notes";

// Direct resource - fixed URI, always available
server.resource(
  "notes-index",
  "notes://index",
  async (uri) => {
    const files = await fs.readdir(NOTES_DIR);
    return {
      contents: [{
        uri: uri.href,
        mimeType: "application/json",
        text: JSON.stringify(
          files.filter(f => f.endsWith(".md"))
               .map(f => ({ id: path.basename(f, ".md"), uri: `notes://${path.basename(f, ".md")}` })),
          null, 2
        ),
      }],
    };
  }
);

// URI template resource - parameterized, one resource per note
server.resource(
  "note",
  new ResourceTemplate("notes://{noteId}", { list: undefined }),
  async (uri, { noteId }) => {
    const filePath = path.join(NOTES_DIR, `${noteId}.md`);
    const content = await fs.readFile(filePath, "utf-8");
    return {
      contents: [{ uri: uri.href, mimeType: "text/markdown", text: content }],
    };
  }
);

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";

const server = new McpServer({ name: "workflow-server", version: "1.0.0" });

server.prompt(
  "code_review",
  "Systematic code review following team conventions and security checklist",
  {
    code: z.string().describe("Code snippet or diff to review"),
    language: z.string().default("typescript").describe("Programming language"),
    focus: z.enum(["security", "performance", "style", "all"]).default("all"),
  },
  async ({ code, language, focus }) => {
    const focusMap = {
      security: "Focus on vulnerabilities: injection, auth bypass, secrets in code, XSS.",
      performance: "Focus on algorithmic complexity, unnecessary allocations, blocking I/O.",
      style: "Focus on naming, structure, documentation, and style guide compliance.",
      all: "Cover security, performance, correctness, and style systematically.",
    };
    return {
      messages: [{
        role: "user",
        content: {
          type: "text",
          text: `Review this ${language} code.\n${focusMap[focus]}\n\nAfter analysis provide:\n1. Critical issues (must fix)\n2. Suggestions (improvements to discuss)\n3. Praise (what was done well)\n\n\`\`\`${language}\n${code}\n\`\`\``,
        },
      }],
    };
  }
);
